  1→import { RichTextPlugin } from "@lexical/react/LexicalRichTextPlugin";
  2→import { ContentEditable } from "@lexical/react/LexicalContentEditable";
  3→import ImageNode from "../Editor/nodes/ImageNode";
  4→import { HeadingNode, QuoteNode } from "@lexical/rich-text";
  5→import { LexicalComposer } from "@lexical/react/LexicalComposer";
  6→import { LexicalErrorBoundary } from "@lexical/react/LexicalErrorBoundary";
  7→import { useLocation, useNavigate, useParams } from "react-router-dom";
  8→import './contentviewer.css'
  9→import { useEffect, useMemo, useRef, useState } from "react";
 10→import { AnimatePresence, motion } from "framer-motion";
 11→import { MoonLoader } from "react-spinners";
 12→import CalculateText from "../postCards/calculateReadingTime";
 13→import ParseContent from "../postCards/parseData";
 14→import { useBookMarkMutation, useFollowMutation, useLikeMutation } from "../../../utils/useMutation";
 15→import { useAuth } from "../../../Context/useAuth";
 16→import CommentSection from "../../comments/comments";
 17→import CanvasViewer from "../Canvas/CanvasViewer";
 18→import debounce from "../../../../helpers/debounce";
 19→import formatCounts from "../../../../helpers/fomatCounts";
 20→import { handleClickProfile } from "../../../../helpers/handleClicks";
 21→import { getFollowsData, getJournalById } from "../../../../API/Api";
 22→import { useQuery } from "@tanstack/react-query";
 23→import VerifiedBadge from "../../Badge/VerifiedBadge";
 24→import { getCanvasWholeText, parseCanvasDoc } from "../../../utils/canvasDoc";
 25→
 26→const normalizeInteractionFlag = (value) => {
 27→    if(typeof value === 'boolean') return value;
 28→    if(typeof value === 'string'){
 29→        const normalized = value.trim().toLowerCase();
 30→        if(normalized === 'true') return true;
 31→        if(normalized === 'false') return false;
 32→    }
 33→    if(typeof value === 'number'){
 34→        return value === 1;
 35→    }
 36→    return Boolean(value);
 37→};
 38→
 39→const normalizeCount = (value) => {
 40→    const number = Number(value);
 41→    if(!Number.isFinite(number) || number < 0){
 42→        return 0;
 43→    }
 44→    return number;
 45→};
 46→
 47→const getNextToggleCount = (isActive, currentCount) => {
 48→    return isActive
 49→        ? Math.max(0, currentCount - 1)
 50→        : currentCount + 1;
 51→};
 52→
 53→const ContentView = () => {
 54→    const navigate = useNavigate();
 55→    const [showBackButton, setShowBackButton] = useState(true);
 56→    const { session, user, openAuthModal } = useAuth();
 57→
 58→    const timeOutRef = useRef();
 59→    const timeOutRefBookmark = useRef();
 60→    const likeInFlightRef = useRef(false);
 61→    const bookmarkInFlightRef = useRef(false);
 62→
 63→    const [showCommentsContainer, setShowCommentsContainer] = useState(false);
 64→    const [isLiked, setIsliked] = useState(false);
 65→    const [likesCount, setLikesCount] = useState(0);
 66→    const [isBookmarked, setIsBookmarked] = useState(false);
 67→    const [bookmarkCounts, setBookmarkCounts] = useState(0);
 68→
 69→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
 70→
 71→    const contentRef = useRef();
 72→
 73→    const theme = {
 74→        paragraph: 'editor-paragraph',
 75→        heading: {
 76→            h1: 'editor-heading-h1',
 77→            h2: 'editor-heading-h2',
 78→            h3: 'editor-heading-h3',
 79→        },
 80→        quote: 'editor-quote',
 81→        text: {
 82→            bold: 'editor-text-bold',
 83→            italic: 'editor-text-italic',
 84→            underline: 'editor-text-underline',
 85→        }
 86→    }
 87→
 88→    const location = useLocation();
 89→    const { journalId } = useParams();
 90→    const statePostData = location.state;
 91→    const shouldFetchPost = !!journalId && (!statePostData || !statePostData?.postType);
 92→
 93→    const { data: fetchedJournalData, isLoading: isLoadingJournalById } = useQuery({
 94→        queryKey: ['journalById', journalId, user?.userData?.[0]?.id],
 95→        queryFn: ({ queryKey }) => getJournalById(queryKey[1], queryKey[2]),
 96→        enabled: shouldFetchPost,
 97→        staleTime: 1000 * 60 * 5,
 98→        refetchOnWindowFocus: false,
 99→    });
100→
101→    const postData = useMemo(() => {
102→        const journal = fetchedJournalData?.journal;
103→        if(journal){
104→            const postType = journal?.post_type || 'text';
105→            const parsedContent = ParseContent(journal?.content);
106→            const canvasDoc = postType === 'canvas' ? parseCanvasDoc(journal?.canvas_doc) : null;
107→            const wholeText = postType === 'canvas'
108→                ? getCanvasWholeText(canvasDoc)
109→                : (parsedContent?.wholeText || '');
110→
111→            return {
112→                postType: postType,
113→                content: journal?.content,
114→                canvasDoc: canvasDoc,
115→                wholeText: wholeText,
116→                title: journal?.title,
117→                userId: journal?.users?.id || journal?.user_id,
118→                name: journal?.users?.name,
119→                avatar: journal?.users?.image_url,
120→                created_at: journal?.created_at,
121→                journalId: journal?.id,
122→                isLiked: journal?.has_liked,
123→                commentsCount: journal?.comment_count?.[0]?.count || 0,
124→                isBookmarked: journal?.has_bookmarked,
125→                likesCount: journal?.like_count?.[0]?.count || 0,
126→                bookmarksCount: journal?.bookmark_count?.[0]?.count || 0,
127→                badge: journal?.users?.badge
128→            };
129→        }
130→
131→        if(!statePostData){
132→            return null;
133→        }
134→
135→        const inferredPostType = statePostData?.postType || (statePostData?.canvasDoc ? 'canvas' : 'text');
136→        const parsedContent = ParseContent(statePostData?.content);
137→        const canvasDoc = inferredPostType === 'canvas' ? parseCanvasDoc(statePostData?.canvasDoc) : null;
138→
139→        return {
140→            postType: inferredPostType,
141→            content: statePostData?.content,
142→            canvasDoc: canvasDoc,
143→            wholeText: inferredPostType === 'canvas'
144→                ? (statePostData?.wholeText || getCanvasWholeText(canvasDoc))
145→                : (statePostData?.wholeText || parsedContent?.wholeText || ''),
146→            title: statePostData?.title,
147→            userId: statePostData?.userId,
148→            name: statePostData?.name,
149→            avatar: statePostData?.avatar,
150→            created_at: statePostData?.created_at,
151→            journalId: statePostData?.journalId,
152→            isLiked: statePostData?.isLiked,
153→            commentsCount: statePostData?.commentsCount || 0,
154→            isBookmarked: statePostData?.isBookmarked,
155→            likesCount: statePostData?.likesCount || 0,
156→            bookmarksCount: statePostData?.bookmarksCount || 0,
157→            badge: statePostData?.badge
158→        };
159→    }, [fetchedJournalData, statePostData]);
160→
161→    const { data: followsData, isLoading: isLoadingFollows } = useQuery({
162→        queryKey: ['followsData', user?.userData?.[0]?.id, postData?.userId],
163→        queryFn: ({ queryKey }) => getFollowsData(queryKey[1], queryKey[2]),
164→        staleTime: 1000 * 60 * 60,
165→        cacheTime: 1000 * 60 * 60,
166→        enabled: !!user?.userData?.[0]?.id && !!postData?.userId,
167→    });
168→
169→    const handleclickUserProfile = handleClickProfile(navigate);
170→
171→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
172→    const handleClickLike = async (e, journalId, receiverId, senderImageUrl, sendername, senderEmail) => {
173→        e.stopPropagation();
174→        if(likeInFlightRef.current){
175→            return;
176→        }
177→        if(!session){
178→            openAuthModal?.();
179→            return;
180→        }
181→        const wasLiked = normalizeInteractionFlag(isLiked);
182→        likeInFlightRef.current = true;
183→        setIsliked(!wasLiked);
184→        setLikesCount((prevCount) => getNextToggleCount(wasLiked, normalizeCount(prevCount)));
185→        mutationLike.mutate(
186→            { journalId, receiverId, senderImageUrl, sendername, senderEmail },
187→            {
188→                onSettled: () => {
189→                    likeInFlightRef.current = false;
190→                }
191→            }
192→        );
193→    }
194→
195→    const mutationBookmark = useBookMarkMutation(session, user?.userData?.[0]?.id);
196→    const handleClickBookmark = async (e, journalId) => {
197→        e.stopPropagation();
198→        if(bookmarkInFlightRef.current){
199→            return;
200→        }
201→        if(!session){
202→            openAuthModal?.();
203→            return;
204→        }
205→        const wasBookmarked = normalizeInteractionFlag(isBookmarked);
206→        bookmarkInFlightRef.current = true;
207→        setIsBookmarked(!wasBookmarked);
208→        setBookmarkCounts((prevCount) => getNextToggleCount(wasBookmarked, normalizeCount(prevCount)));
209→        let response = null;
210→        try {
211→            response = await mutationBookmark.mutateAsync({ journalId });
212→        } finally {
213→            bookmarkInFlightRef.current = false;
214→        }
215→        
216→        if(timeOutRefBookmark.current){
217→            clearTimeout(timeOutRefBookmark.current);
218→        }
219→        if (response?.message === 'success') {
220→            setBookmarkedMessage('Post was added to your Bookmarks'); 
221→        } else if(response?.message === 'deleted'){
222→            setBookmarkedMessage('Post was removed from your Bookmarks');
223→        }
224→            
225→        timeOutRefBookmark.current = setTimeout(() => {
226→            setBookmarkedMessage('');
227→        }, 1500);
228→
229→    }
230→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
231→
232→    const mutationFollow = useFollowMutation(session);
233→    const handleClickFollow = async (e, followingId, followerId) => {
234→        e.stopPropagation();
235→        mutationFollow.mutate({ followingId, followerId });
236→    }
237→    const debounceClickFollow = debounce(handleClickFollow, 100);
238→
239→    const handleBackLocation = (e) => {
240→        e.stopPropagation();
241→        window.history.back();
242→    }
243→
244→    const hanldeClickComments = (e) => {
245→        e.stopPropagation();
246→        setShowCommentsContainer(true);
247→    }
248→
249→    const handleRemixCanvas = (e) => {
250→        e.stopPropagation();
251→        if(!session){
252→            return;
253→        }
254→
255→        const sourceTitle = typeof postData?.title === 'string' ? postData.title.trim() : '';
256→        const remixTitle = sourceTitle.toLowerCase().startsWith('remix:')
257→            ? sourceTitle
258→            : `Remix: ${sourceTitle || 'Canvas'}`;
259→
260→        navigate('/home', {
261→            state: {
262→                openEditor: true,
263→                editorMode: 'canvas',
264→                initialTitle: remixTitle,
265→                initialCanvasDoc: postData?.canvasDoc || null,
266→                remixSource: {
267→                    journalId: postData?.journalId,
268→                    authorName: postData?.name || 'Unknown'
269→                }
270→            }
271→        });
272→    }
273→
274→    const handleCLoseComments = () => {
275→        setShowCommentsContainer(false);
276→    }
277→
278→    useEffect(() => {
279→        if (!postData) return;
280→        setLikesCount(normalizeCount(postData?.likesCount));
281→        setBookmarkCounts(normalizeCount(postData?.bookmarksCount));
282→        setIsliked(normalizeInteractionFlag(postData?.isLiked));
283→        setIsBookmarked(normalizeInteractionFlag(postData?.isBookmarked));
284→    }, [postData?.likesCount, postData?.bookmarksCount, postData?.isLiked, postData?.isBookmarked]);
285→
286→    useEffect(() => {
287→        if (postData?.title) {
288→            document.title = `${postData.title} | Iskrib`;
289→            return () => {
290→                document.title = 'Iskrib';
291→            };
292→        }
293→
294→        document.title = 'Iskrib';
295→    }, [postData?.title]);
296→
297→    useEffect(() => {
298→        const hideBackBttn = () => {
299→            setShowBackButton(false);
300→            if (timeOutRef.current) {
301→                clearTimeout(timeOutRef.current);
302→            }
303→            timeOutRef.current = setTimeout(() => {
304→                setShowBackButton(true);
305→            }, 300);
306→        }
307→
308→        document.addEventListener('scroll', hideBackBttn, true);
309→        return () => {
310→            if (timeOutRef.current) {
311→                clearTimeout(timeOutRef.current);
312→            }
313→            document.removeEventListener('scroll', hideBackBttn, true);
314→        }
315→    }, []);
316→
317→    if (isLoadingJournalById || isLoadingFollows) {
318→        return (
319→            <div className="cv-loading">
320→                <MoonLoader loading={isLoadingJournalById || isLoadingFollows} color="var(--loader-color)" size={25} />
321→            </div>
322→        )
323→    }
324→
325→    if (!postData) {
326→        return (
327→            <div className="cv-loading">
328→                <p>Post is unavailable.</p>
329→                <button onClick={handleBackLocation} className="cv-back-btn" style={{ marginTop: "12px" }}>
330→                    Go back
331→                </button>
332→            </div>
333→        )
334→    }
335→
336→    return (
337→        <>
338→            {showCommentsContainer && (
339→                <AnimatePresence>
340→                    <CommentSection onclose={handleCLoseComments} postId={postData?.journalId} receiverId={postData?.userId} />
341→                </AnimatePresence>
342→            )}
343→
344→            <div ref={contentRef} className="cv-container">
345→                {/* Back header */}
346→                <AnimatePresence>
347→                    {showBackButton && (
348→                        <motion.div
349→                            className="cv-header"
350→                            initial={{ opacity: 0 }}
351→                            animate={{ opacity: 1, transition: { duration: 0.15 } }}
352→                            exit={{ opacity: 0, transition: { duration: 0.15 } }}
353→                        >
354→                            <button onClick={handleBackLocation} className="cv-back-btn">
355→                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 -960 960 960">
356→                                    <path d="M360-240 120-480l240-240 56 56-144 144h568v80H272l144 144-56 56Z" />
357→                                </svg>
358→                            </button>
359→                            <p className="cv-header-label">Post</p>
360→                        </motion.div>
361→                    )}
362→                </AnimatePresence>
363→
364→                <article className="cv-article">
365→                    {/* Title */}
366→                    <h1 className="cv-title">{postData?.title}</h1>
367→
368→                    {/* Metadata */}
369→                    <div className="cv-meta">
370→                        <div
371→                            onClick={(e) => handleclickUserProfile(e, user?.userData[0].id, postData?.userId)}
372→                            className={`cv-avatar-wrap ${postData?.badge === 'legend' ? 'cv-avatar-ring-legend' : postData?.badge === 'og' ? 'cv-avatar-ring-og' : ''}`}
373→                        >
374→                            <img src={postData?.avatar || '/assets/profile.jpg'} className="cv-avatar" alt="user avatar" />
375→                        </div>
376→                        <div className="cv-meta-info">
377→                            <div className="cv-meta-top">
378→                                <span
379→                                    onClick={(e) => handleclickUserProfile(e, user?.userData[0].id, postData?.userId)}
380→                                    className="cv-author-name"
381→                                >
382→                                    {postData?.name}
383→                                </span>
384→                                <VerifiedBadge badge={postData?.badge} size={16} />
385→                                {postData?.userId !== user?.userData?.[0].id && (
386→                                    <button
387→                                        onClick={(e) => debounceClickFollow(e, postData?.userId, user?.userData?.[0].id)}
388→                                        className={`cv-follow-btn ${followsData?.isFollowing ? 'cv-follow-btn--following' : ''}`}
389→                                    >
390→                                        {followsData?.isFollowing ? 'Following' : 'Follow'}
391→                                    </button>
392→                                )}
393→                            </div>
394→                            <div className="cv-meta-bottom">
395→                                <span className="cv-date">
396→                                    {new Date(postData?.created_at).toLocaleDateString('en-US', {
397→                                        month: 'long',
398→                                        day: '2-digit',
399→                                        year: 'numeric',
400→                                    })}
401→                                </span>
402→                                <span className="cv-meta-dot">&middot;</span>
403→                                <span className="cv-read-time">{CalculateText(postData?.wholeText)}</span>
404→                            </div>
405→                        </div>
406→                    </div>
407→
408→                    {/* Action bar */}
409→                    <div className="cv-actions">
410→                        <button
411→                            className="cv-action-btn"
412→                            onClick={(e) => handleClickLike(e, postData?.journalId, postData?.userId, user?.userData?.[0].image_url, user?.userData?.[0].name, user?.userData?.[0].user_email)}
