 1→import { useEffect, useMemo, useRef, useState } from "react";
 2→import { parseCanvasDoc } from "../../../utils/canvasDoc";
 3→import CanvasSurface, { buildSortedCanvasObjects, getCanvasStageHeight } from "./CanvasSurface";
 4→import styles from "./CanvasEditor.module.css";
 5→import "./canvas.css";
 6→
 7→const CANVAS_MAX_WIDTH = 560;
 8→
 9→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
10→
11→const CanvasViewer = ({canvasDoc}) => {
12→    const shellRef = useRef(null);
13→    const stageRef = useRef(null);
14→
15→    const [shellWidth, setShellWidth] = useState(CANVAS_MAX_WIDTH);
16→
17→    const parsedCanvasDoc = useMemo(() => parseCanvasDoc(canvasDoc), [canvasDoc]);
18→    const sortedObjects = useMemo(
19→        () => buildSortedCanvasObjects(parsedCanvasDoc?.snippets || [], parsedCanvasDoc?.images || []),
20→        [parsedCanvasDoc?.images, parsedCanvasDoc?.snippets]
21→    );
22→
23→    useEffect(() => {
24→        const getContentWidth = () => {
25→            const el = shellRef.current;
26→            if(!el){
27→                return CANVAS_MAX_WIDTH;
28→            }
29→            const style = getComputedStyle(el);
30→            const paddingLeft = parseFloat(style.paddingLeft) || 0;
31→            const paddingRight = parseFloat(style.paddingRight) || 0;
32→            return el.clientWidth - paddingLeft - paddingRight;
33→        };
34→
35→        const updateShellWidth = () => {
36→            setShellWidth(getContentWidth());
37→        };
38→
39→        updateShellWidth();
40→        window.addEventListener("resize", updateShellWidth);
41→
42→        let resizeObserver = null;
43→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
44→            resizeObserver = new ResizeObserver(updateShellWidth);
45→            resizeObserver.observe(shellRef.current);
46→        }
47→
48→        return () => {
49→            window.removeEventListener("resize", updateShellWidth);
50→            if(resizeObserver){
51→                resizeObserver.disconnect();
52→            }
53→        };
54→    }, []);
55→
56→    const stageWidth = useMemo(() => Math.max(240, Math.min(CANVAS_MAX_WIDTH, shellWidth)), [shellWidth]);
57→    const stageHeight = getCanvasStageHeight(stageWidth, parsedCanvasDoc?.meta?.aspectRatio);
58→    const doodleStrokeScale = useMemo(() => clamp(stageWidth / CANVAS_MAX_WIDTH, 0.45, 1), [stageWidth]);
59→
60→    return (
61→        <div className={`${styles.editorRoot} ${styles.viewerRoot}`}>
62→            <div
63→                ref={shellRef}
64→                className={`${styles.stageShell} ${parsedCanvasDoc?.meta?.theme === "dark" ? styles.isDark : ""}`}
65→            >
66→                <div className={styles.stageFrame}>
67→                    <CanvasSurface
68→                        stageRef={stageRef}
69→                        viewportWidth={stageWidth}
70→                        viewportHeight={stageHeight}
71→                        stageWidth={stageWidth}
72→                        stageHeight={stageHeight}
73→                        gridEnabled={parsedCanvasDoc?.meta?.gridEnabled}
74→                        theme={parsedCanvasDoc?.meta?.theme}
75→                        doodles={parsedCanvasDoc?.doodles || []}
76→                        doodleStrokeScale={doodleStrokeScale}
77→                        sortedObjects={sortedObjects}
78→                        activeTool="select"
79→                        className={styles.stage}
80→                    />
81→                </div>
82→            </div>
83→        </div>
84→    );
85→};
86→
87→export default CanvasViewer;
